import { useState, useRef, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate, useLocation } from "react-router-dom";
import { Image, Video, X, Loader2, Calendar, MapPin, Gift, ArrowLeft } from "lucide-react";
import PostPointsRulesDialog from "@/components/community/PostPointsRulesDialog";
import MultiRestaurantSelectDrawer from "@/components/community/MultiRestaurantSelectDrawer";
import ActivitySelectDrawer from "@/components/community/ActivitySelectDrawer";
import EmojiPicker from "@/components/community/EmojiPicker";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { supabase } from "@/integrations/supabase/client";
import { useCreatePost, useMerchantRestaurant, useHasPostedToday } from "@/hooks/useCommunityPosts";
import { useActivities } from "@/hooks/useActivities";
import { useRestaurants } from "@/hooks/useRestaurants";
import { useUserRole } from "@/hooks/useUserRole";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useSmartBack } from "@/hooks/useSmartBack";
import { toast } from "sonner";

const CreatePostPage = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();
  const goBack = useSmartBack("/community/create");
  const { getLocalizedField } = useLocalizedContent();
  const createPost = useCreatePost();
  const { data: activities } = useActivities();
  const { data: restaurants } = useRestaurants();
  const { isMerchant, isAdmin, isSupervisor } = useUserRole();
  const { data: merchantRestaurant } = useMerchantRestaurant();
  const { data: hasPostedToday, isLoading: checkingPost } = useHasPostedToday();

  const [content, setContent] = useState("");
  const [imageUrls, setImageUrls] = useState<string[]>([]);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [activityId, setActivityId] = useState<string>("");
  const [restaurantIds, setRestaurantIds] = useState<string[]>([]);
  const [uploading, setUploading] = useState(false);
  const [restaurantOpen, setRestaurantOpen] = useState(false);
  const [activityOpen, setActivityOpen] = useState(false);
  const [showRestaurantError, setShowRestaurantError] = useState(false);
  const [aiRecipeSource, setAiRecipeSource] = useState<Record<string, any> | null>(null);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const isRegularUser = !isMerchant && !isSupervisor && !isAdmin;
  const activeActivities = activities?.filter((a) => a.status === "published") || [];

  // Prefill from AI recipe navigation state
  useEffect(() => {
    const state = location.state as any;
    if (state?.prefillContent) setContent(state.prefillContent);
    if (state?.prefillVideoUrl) setVideoUrl(state.prefillVideoUrl);
    if (state?.prefillAiRecipeSource) setAiRecipeSource(state.prefillAiRecipeSource);
    if (state) navigate(location.pathname, { replace: true, state: {} });
  }, []);

  useEffect(() => {
    if (isMerchant && merchantRestaurant) {
      setRestaurantIds([merchantRestaurant.id]);
    }
  }, [isMerchant, merchantRestaurant]);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    if (imageUrls.length + files.length > 9) {
      toast.error(t("community.maxImages", "最多上传9张图片"));
      return;
    }
    setUploading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");
      const uploadedUrls: string[] = [];
      for (const file of Array.from(files)) {
        const fileExt = file.name.split(".").pop();
        const fileName = `${user.id}/${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
        const { error: uploadError } = await supabase.storage.from("community-posts").upload(fileName, file);
        if (uploadError) throw uploadError;
        const { data: { publicUrl } } = supabase.storage.from("community-posts").getPublicUrl(fileName);
        uploadedUrls.push(publicUrl);
      }
      setImageUrls((prev) => [...prev, ...uploadedUrls]);
    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploading(false);
      if (imageInputRef.current) imageInputRef.current.value = "";
    }
  };

  const extractVideoFirstFrame = (videoFile: File): Promise<Blob> => {
    return new Promise((resolve, reject) => {
      const video = document.createElement("video");
      const canvas = document.createElement("canvas");
      const ctx = canvas.getContext("2d");
      video.preload = "auto";
      video.muted = true;
      video.playsInline = true;
      let hasResolved = false;
      const captureFrame = () => {
        if (hasResolved || video.videoWidth === 0 || video.videoHeight === 0) return;
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          canvas.toBlob((blob) => {
            if (blob && blob.size > 0) {
              hasResolved = true;
              video.pause();
              URL.revokeObjectURL(video.src);
              resolve(blob);
            } else reject(new Error("Failed to create blob"));
          }, "image/jpeg", 0.85);
        }
      };
      video.onloadedmetadata = () => { video.currentTime = 0.1; };
      video.onseeked = () => { setTimeout(captureFrame, 100); };
      video.onerror = () => { URL.revokeObjectURL(video.src); reject(new Error("Failed to load video")); };
      setTimeout(() => { if (!hasResolved) { URL.revokeObjectURL(video.src); reject(new Error("Timeout")); } }, 10000);
      video.src = URL.createObjectURL(videoFile);
      video.load();
    });
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 100 * 1024 * 1024) {
      toast.error(t("community.videoTooLarge", "视频不能超过100MB"));
      return;
    }
    setUploading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");
      const videoExt = file.name.split(".").pop();
      const videoFileName = `${user.id}/${Date.now()}.${videoExt}`;
      const { error: videoError } = await supabase.storage.from("community-posts").upload(videoFileName, file);
      if (videoError) throw videoError;
      const { data: { publicUrl: videoPublicUrl } } = supabase.storage.from("community-posts").getPublicUrl(videoFileName);
      setVideoUrl(videoPublicUrl);
      try {
        toast.info(t("community.extractingCover", "正在提取视频封面..."));
        const coverBlob = await extractVideoFirstFrame(file);
        const coverFileName = `${user.id}/${Date.now()}-cover.jpg`;
        const { error: coverError } = await supabase.storage.from("community-posts").upload(coverFileName, coverBlob);
        if (!coverError) {
          const { data: { publicUrl: coverUrl } } = supabase.storage.from("community-posts").getPublicUrl(coverFileName);
          setImageUrls((prev) => [coverUrl, ...prev]);
          toast.success(t("community.coverExtracted", "封面已自动生成"));
        }
      } catch (coverError) {
        console.warn("Cover extraction failed:", coverError);
      }
    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploading(false);
      if (videoInputRef.current) videoInputRef.current.value = "";
    }
  };

  const removeImage = (index: number) => setImageUrls((prev) => prev.filter((_, i) => i !== index));
  const removeVideo = () => {
    setVideoUrl(null);
    setImageUrls((prev) => (prev.length > 0 && prev[0].includes("-cover.jpg") ? prev.slice(1) : prev));
  };

  const getMerchantRestaurantName = () => {
    if (!merchantRestaurant) return t("community.noRestaurant", "未关联餐厅");
    return getLocalizedField(merchantRestaurant, "name");
  };

  const handleSubmit = async () => {
    setShowRestaurantError(false);
    if (!content.trim()) { toast.error(t("community.contentRequired", "请输入内容")); return; }
    if (isRegularUser && restaurantIds.length === 0) {
      setShowRestaurantError(true);
      toast.error(t("community.restaurantRequired", "请选择餐厅"));
      return;
    }
    await createPost.mutateAsync({
      content,
      image_urls: imageUrls,
      video_url: videoUrl || undefined,
      activity_id: activityId || undefined,
      restaurant_ids: restaurantIds.length > 0 ? restaurantIds : undefined,
      ai_recipe_source: aiRecipeSource || undefined,
    });
    navigate("/community");
  };

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <input ref={imageInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleImageUpload} />
      <input ref={videoInputRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />

      {/* Header */}
      <div className="border-b bg-background sticky top-0 z-10">
        <div className="container mx-auto max-w-2xl flex items-center justify-between px-4 py-3">
          <button type="button" onClick={goBack} className="p-1 -ml-1 hover:bg-muted rounded-md transition-colors">
            <ArrowLeft className="h-5 w-5" />
          </button>
          <span className="font-medium text-sm">{t("community.postType.post", "发布帖子")}</span>
          <Button
            size="sm"
            onClick={handleSubmit}
            disabled={createPost.isPending || !content.trim()}
            className="rounded-full px-6"
          >
            {createPost.isPending && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
            {t("community.publish", "发布")}
          </Button>
        </div>
      </div>

      {/* Points hint */}
      {!checkingPost && !hasPostedToday && (
        <div className="border-b border-primary/30 bg-primary/10">
          <div className="container mx-auto max-w-2xl flex items-center justify-between gap-2 px-4 py-2 text-sm text-primary">
            <div className="flex items-center gap-2">
              <Gift className="h-4 w-4 shrink-0" />
              <span>{t("community.dailyPointsHint", "每日发布首个帖子可获得5积分！")}</span>
            </div>
            <PostPointsRulesDialog />
          </div>
        </div>
      )}

      {/* Main content */}
      <div className="flex-1 container mx-auto max-w-2xl px-4">
        {/* Text area */}
        <div className="py-4">
          <Textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder={t("community.contentPlaceholder", "分享你的想法...")}
            className="min-h-[200px] border-none shadow-none resize-none focus-visible:ring-0 p-0 text-base whitespace-pre-wrap"
            autoFocus
          />
        </div>

        {/* Media preview */}
        {(imageUrls.length > 0 || videoUrl) && (
          <div className="pb-4">
            {imageUrls.length > 0 && (
              <div className={`grid gap-2 mb-3 ${imageUrls.length === 1 ? "grid-cols-1 max-w-xs" : imageUrls.length <= 4 ? "grid-cols-2 max-w-md" : "grid-cols-3 max-w-lg"}`}>
                {imageUrls.map((url, index) => (
                  <div key={index} className="relative aspect-square rounded-lg overflow-hidden bg-muted group">
                    <img src={url} alt="" className="w-full h-full object-cover" />
                    <button
                      type="button"
                      onClick={() => removeImage(index)}
                      className="absolute top-1.5 right-1.5 p-1 bg-black/60 rounded-full text-white opacity-0 group-hover:opacity-100 hover:bg-black/80 transition-opacity"
                    >
                      <X className="h-3.5 w-3.5" />
                    </button>
                  </div>
                ))}
              </div>
            )}
            {videoUrl && (
              <div className="relative rounded-lg overflow-hidden bg-black group max-w-md">
                <video src={videoUrl} controls className="w-full max-h-[280px]" preload="metadata" />
                <button
                  type="button"
                  onClick={removeVideo}
                  className="absolute top-2 right-2 p-1 bg-black/60 rounded-full text-white opacity-0 group-hover:opacity-100 hover:bg-black/80 transition-opacity"
                >
                  <X className="h-4 w-4" />
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Bottom toolbar - sticky */}
      <div className="border-t bg-background sticky bottom-0 z-10">
        <div className="container mx-auto max-w-2xl px-4 py-2.5">
          <div className="flex items-center gap-1 flex-wrap">
            {/* Media buttons */}
            <button
              type="button"
              onClick={() => imageInputRef.current?.click()}
              disabled={uploading || imageUrls.length >= 9}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-muted-foreground hover:text-foreground hover:bg-muted disabled:opacity-40 transition-colors"
            >
              <Image className="h-5 w-5" />
              <span className="text-sm">{t("community.photo", "照片")}</span>
            </button>
            <button
              type="button"
              onClick={() => videoInputRef.current?.click()}
              disabled={uploading || !!videoUrl}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-muted-foreground hover:text-foreground hover:bg-muted disabled:opacity-40 transition-colors"
            >
              <Video className="h-5 w-5" />
              <span className="text-sm">{t("community.video", "视频")}</span>
            </button>

            <div className="w-px h-5 bg-border mx-1" />

            <EmojiPicker onSelect={(emoji) => setContent((prev) => prev + emoji)} />

            <div className="w-px h-5 bg-border mx-1" />

            {/* Restaurant */}
            <div className={`flex items-center gap-2 px-2 py-1 rounded-lg ${showRestaurantError && isRegularUser && restaurantIds.length === 0 ? "text-destructive" : ""}`}>
              <MapPin className={`h-4 w-4 shrink-0 ${showRestaurantError && isRegularUser && restaurantIds.length === 0 ? "text-destructive" : "text-muted-foreground"}`} />
              {isMerchant ? (
                <span className="text-sm text-muted-foreground truncate">{getMerchantRestaurantName()}</span>
              ) : (
                <MultiRestaurantSelectDrawer
                  open={restaurantOpen}
                  onOpenChange={(open) => { setRestaurantOpen(open); if (open) setShowRestaurantError(false); }}
                  value={restaurantIds}
                  onSelect={(ids) => { setRestaurantIds(ids); setShowRestaurantError(false); }}
                  restaurants={restaurants || []}
                  required={isRegularUser}
                />
              )}
            </div>

            <div className="w-px h-5 bg-border mx-1" />

            {/* Activity */}
            <div className="flex items-center gap-2 px-2 py-1">
              <Calendar className="h-4 w-4 text-muted-foreground shrink-0" />
              <ActivitySelectDrawer
                open={activityOpen}
                onOpenChange={setActivityOpen}
                value={activityId}
                onSelect={setActivityId}
                activities={activeActivities}
              />
            </div>

            {uploading && <Loader2 className="h-4 w-4 animate-spin ml-auto text-muted-foreground" />}
          </div>
          {showRestaurantError && isRegularUser && restaurantIds.length === 0 && (
            <p className="text-xs text-destructive mt-1">{t("community.restaurantRequired", "请选择餐厅")}</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default CreatePostPage;
